56.     app.UseHsts();
57. }
58. app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
59. app.UseHttpsRedirection();
60. 
61. app.UseAntiforgery();
62. 
63. app.MapStaticAssets();
64. app.MapRazorComponents<App>()
65.     .AddInteractiveServerRenderMode()
66.     .AddInteractiveWebAssemblyRenderMode()
67.     .AddAdditionalAssemblies(typeof(ShipmentTracker.Client._Imports).Assembly);
68. 
69. // Add additional endpoints required by the Identity /Account Razor components.
