cd /tmp/sv-081b3ceef1e8470db080041a73c74f1b/ShipmentTracker

# Create directories
mkdir -p ShipmentTracker.Client/Models ShipmentTracker.Client/Services ShipmentTracker/Services

# 1. Shared Model
cat > ShipmentTracker.Client/Models/Shipment.cs << 'EOF'
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime ShippedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
EOF

# 2. Service Interface
cat > ShipmentTracker.Client/Services/IShipmentService.cs << 'EOF'
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<List<Shipment>> GetShipmentsByCustomerAsync(string email);
    Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus);
}
EOF

# 3. Client HTTP implementation
cat > ShipmentTracker.Client/Services/ShipmentHttpService.cs << 'EOF'
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient httpClient) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("/api/shipments") ?? [];
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await httpClient.GetFromJsonAsync<Shipment?>($"/api/shipments/track/{trackingNumber}");
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string email)
    {
        return await httpClient.GetFromJsonAsync<List<Shipment>>("/api/shipments/my") ?? [];
    }

    public async Task UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        await httpClient.PutAsJsonAsync($"/api/shipments/{id}/status", new { NewStatus = newStatus });
    }
}
EOF

# 4. Server-side EF entity
cat > ShipmentTracker/Data/ShipmentEntity.cs << 'EOF'
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

