# Create Dispatcher page
cat > ShipmentTracker.Client/Pages/Dispatcher.razor << 'EOF'
@page "/dispatcher"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Filter by destination or tracking number..."
           @bind="filterText" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Shipped</th>
                <th>Est. Delivery</th>
                <th>Update Status</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td><span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></td>
                    <td>@shipment.ShippedDate.ToString("yyyy-MM-dd")</td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm"
                                value="@((int)shipment.Status)"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;

    private IEnumerable<Shipment> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrEmpty(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "info",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "warning",
        _ => "secondary"
    };
}
EOF

# Create TrackShipment page
cat > ShipmentTracker.Client/Pages/TrackShipment.razor << 'EOF'
@page "/track"
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Shipment</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @bind:event="oninput" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackAsync">Track</button>
        </div>
    </div>
</div>

@if (searched)
{
    @if (shipment is not null)
    {
        <div class="card">
            <div class="card-header">
                <strong>@shipment.TrackingNumber</strong>
            </div>
            <div class="card-body">
                <p><strong>Status:</strong> <span class="badge bg-@GetStatusColor(shipment.Status)">@shipment.Status</span></p>
                <p><strong>Origin:</strong> @shipment.Origin</p>
                <p><strong>Destination:</strong> @shipment.Destination</p>
                <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("yyyy-MM-dd")</p>
                <p><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "N/A")</p>
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">Shipment not found. Please check the tracking number and try again.</div>
    }
}

@code {
    private string trackingNumber = string.Empty;
    private Shipment? shipment;
    private bool searched;

    private async Task TrackAsync()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        searched = true;
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(trackingNumber.Trim());
        }
        catch (HttpRequestException)
        {
            shipment = null;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackAsync();
    }

    private static string GetStatusColor(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "secondary",
        ShipmentStatus.InTransit => "primary",
        ShipmentStatus.OutForDelivery => "info",
        ShipmentStatus.Delivered => "success",
        ShipmentStatus.Delayed => "warning",
        _ => "secondary"
    };
}
EOF

